# WARNING - Generated by {fusen} from dev/flat_crypt_r.Rmd: do not edit by hand # nolint: line_length_linter.

#' Industrialized dataset variables encryption.
#'
#' This function consolidates a set of procedures made to encrypt
#' variables from datasets. Variables to encrypt and input datasets can
#' be in any number, following user's needs.
#'
#' Since Phase 1.D.6.b, `crypt_r()` is **non-blocking**: it builds a
#' `cryptR_job` (one `mirai` task per filtered mask row) and returns
#' immediately. The caller inspects / waits / finalises the job through
#' the companion API (see *Value* and *See Also*). A per-row failure
#' does not interrupt the other rows â€” the failure is captured on the
#' corresponding task and surfaces via [cryptR_status()].
#'
#' @param mask_folder_path Folder path of the excel mask.
#' @param mask_file File name (with extension) of the excel mask.
#' @param output_path Folder path where the encrypted datasets
#' will be created.
#' @param intermediate_path Folder path where intermediate files
#' (correspondence tables for e.g) will be created.
#' @param encryption_key Character vector.
#' @param algorithm Algorithm to use.
#' From digest::digest()'s algo argument.
#' @param correspondence_table Logical vector. If TRUE, the correspondence tables will computed
#' and stored in the indicated intermediate_path.
#' @param engine One of `"auto"`, `"in_memory"`, `"streaming"`.
#'   Selects the per-row processing engine. `"auto"` (default) and
#'   `"streaming"` both route parquet-in/parquet-out and csv-in/csv-out
#'   to the streaming engines (arrow Scanner by chunks, progressive
#'   write); mixed or non-streamable endpoints (rds, xlsx, parquetâ†’csv,
#'   csvâ†’parquet) silently fall back to `"in_memory"` to preserve
#'   non-regression. `"in_memory"` always reads the full input into
#'   RAM (historical behaviour). Introduced in Phase 1.D.4.a
#'   (plumbing), streaming engines in 1.D.4.b/c, auto-routing rule in
#'   1.D.4.d.
#' @param chunk_size Integer. Number of rows per chunk when the
#'   effective engine is streaming. Ignored by `"in_memory"` (and by
#'   `"auto"` / `"streaming"` when falling back to in_memory). Default
#'   `1e6`.
#' @param n_workers Integer or `NULL`. Number of `mirai` daemons to
#'   spawn for the dispatch. When `NULL` (default), `crypt_r()` picks
#'   `min(parallel::detectCores() - 1, n_rows, 8L)` (floored at 1).
#'   If daemons are already running on the default profile when
#'   `crypt_r()` is called, `n_workers` is ignored and the existing
#'   daemons are reused â€” the user retains control and
#'   [cryptR_collect()] will not tear them down. Added in Phase 1.D.6.b.
#' @return A [`cryptR_job`][cryptR_status] object carrying one `mirai`
#'   task per filtered mask row. Inspect with [cryptR_status()]; block
#'   with [cryptR_wait()]; finalise (write the recap log and, when
#'   applicable, tear down the daemons) with [cryptR_collect()].
#' @seealso [cryptR_status()], [cryptR_wait()], [cryptR_collect()],
#'   [get_correspondence_tables()].
#' @importFrom magrittr %>%
#' @export
#'
crypt_r <- function (mask_folder_path, mask_file,
                     output_path, intermediate_path,
                     encryption_key, algorithm = "md5",
                     correspondence_table = TRUE,
                     engine = c("auto", "in_memory", "streaming"),
                     chunk_size = 1e6L,
                     n_workers = NULL) {

  requireNamespace("magrittr")
  requireNamespace("mirai")

  engine <- match.arg(engine)
  stopifnot(is.numeric(chunk_size),
            length(chunk_size) == 1L,
            !is.na(chunk_size),
            chunk_size > 0)
  chunk_size <- as.integer(chunk_size)

  if (!is.null(n_workers)) {
    stopifnot(is.numeric(n_workers), length(n_workers) == 1L,
              !is.na(n_workers), n_workers >= 1)
    n_workers <- as.integer(n_workers)
  }

  # The Excel mask:
  mask <-
    rio::import(file.path(mask_folder_path, mask_file)) %>%

    # Without eventual blank lines in the mask (for visualization ease):
    dplyr::filter_all(dplyr::any_vars(! is.na(.))) %>%

    # Inserting a row_number (useful for technical reasons):
    dplyr::mutate(row_number = dplyr::row_number()) %>%

    # Keep only lines on datasets the user want to encrypt:
    dplyr::filter(to_encrypt == "X")

  # Check eventual duplicated file names, if there is, add indication
  # to keep file names unique:
  mask <-

    dplyr::mutate(
      mask,
      dupl_encrypted_file = duplicated(encrypted_file),
      ndupl_encrypted_file = cumsum(dupl_encrypted_file) %>%
        (\(n) paste0("DUPL", n)),
      encrypted_file =
        ifelse(dupl_encrypted_file,
               paste0(ndupl_encrypted_file, "_",
                      encrypted_file),
               encrypted_file))

  n_rows <- nrow(mask)

  # Empty mask: nothing to do. Return a trivial cryptR_job so the caller
  # can still introspect / collect uniformly. The watcher short-circuits
  # to an immediate finalize on empty-mask jobs (an empty xlsx log is
  # still produced for uniformity).
  if (n_rows == 0L) {
    job <- .new_cryptR_job(
      tasks                = list(),
      mask_rows            = mask,
      output_path          = output_path,
      intermediate_path    = intermediate_path,
      daemons_owned_by_job = FALSE)
    return(.start_watcher(job))
  }

  # --- n_workers resolution --------------------------------------------
  # Heuristic: leave one core to the OS, cap at 8 to avoid hammering
  # shared machines, never exceed the number of tasks.
  if (is.null(n_workers)) {
    cores <- tryCatch(parallel::detectCores(logical = TRUE),
                      error = function(e) 2L)
    if (is.null(cores) || is.na(cores) || cores < 2L) cores <- 2L
    n_workers <- max(1L, min(as.integer(cores) - 1L, n_rows, 8L))
  } else {
    n_workers <- max(1L, min(n_workers, n_rows))
  }

  # --- Daemons ownership ------------------------------------------------
  # If daemons are already running on the default profile, we reuse them
  # and leave teardown to the user. If none are running, we set up our
  # own and flag the job so cryptR_collect() tears them down at the end.
  # `.n_workers_active()` returns NA if mirai::status() errors outright;
  # in that case we fall back to "no daemons active" (0L) and spawn our
  # own, matching the previous open-coded tryCatch behaviour.
  n_existing <- .n_workers_active()
  if (is.na(n_existing)) n_existing <- 0L

  daemons_owned_by_job <- FALSE
  if (n_existing == 0L) {
    mirai::daemons(n_workers)
    daemons_owned_by_job <- TRUE
  }

  # Load the package in each daemon so `cryptRopen:::.process_mask_row`
  # resolves. Silently tolerate failures: if cryptRopen is not installed
  # in the daemon's library paths (dev session), task dispatch below will
  # still surface the lookup error as a failed task via cryptR_status().
  try(mirai::everywhere({
    suppressPackageStartupMessages(requireNamespace("cryptRopen",
                                                    quietly = TRUE))
  }), silent = TRUE)

  # --- Dispatch one mirai task per filtered mask row -------------------
  input_paths <- paste0(mask$folder_path, "/", mask$file)

  tasks <- purrr::map(seq_len(n_rows), \(i) {
    sm_i         <- mask[i, , drop = FALSE]
    input_path_i <- input_paths[[i]]

    mirai::mirai(
      cryptRopen:::.process_mask_row(
        sm                   = sm_i,
        input_path           = input_path_i,
        output_path          = output_path,
        intermediate_path    = intermediate_path,
        encryption_key       = encryption_key,
        algorithm            = algorithm,
        correspondence_table = correspondence_table,
        engine               = engine,
        chunk_size           = chunk_size),
      sm_i                 = sm_i,
      input_path_i         = input_path_i,
      output_path          = output_path,
      intermediate_path    = intermediate_path,
      encryption_key       = encryption_key,
      algorithm            = algorithm,
      correspondence_table = correspondence_table,
      engine               = engine,
      chunk_size           = chunk_size)
  })

  names(tasks) <- as.character(mask$encrypted_file)

  job <- .new_cryptR_job(
    tasks                = tasks,
    mask_rows            = mask,
    output_path          = output_path,
    intermediate_path    = intermediate_path,
    daemons_owned_by_job = daemons_owned_by_job)

  # Phase 1.D.6.c: register the auto-watcher so the recap xlsx log is
  # written as soon as the last mirai task resolves, without the user
  # having to call cryptR_collect() manually. Idempotent wrt a manual
  # collect â€” see R/cryptR_watcher.R + `.log_already_written()`.
  .start_watcher(job)
}

#' Build the typed per-row result list returned by the engines.
#'
#' Introduced in Phase 1.D.6.c. The three engines
#' (`.process_mask_row_in_memory()`, `.process_mask_row_streaming()`,
#' `.process_mask_row_csv_streaming()`) previously returned
#' `invisible(NULL)` and communicated results only through disk side
#' effects (+ `.cryptRopen_env` stored TC). That was sufficient for the
#' in-process use (tests calling the engine directly on the same R
#' session), but when a worker runs inside a `mirai` daemon its private
#' env is unreachable from the client; the recap log also needs
#' per-row metrics that are only cheap to compute inside the worker.
#'
#' The engines now assemble a structured list via this helper; the
#' mirai dispatcher ships it back to the parent as `task$data`, which
#' `cryptR_collect()` consumes to (a) re-populate `.cryptRopen_env`
#' with the correspondence tables captured inside the workers and
#' (b) write the `log_crypt_r_<timestamp>.xlsx` recap.
#'
#' Disk outputs and `.cryptRopen_env` side effects are *unchanged* â€”
#' this helper only packages additional metadata for the parent. Tests
#' that exercise the engines directly still pass because they read
#' from disk or `get_correspondence_tables()`, not from the return
#' value.
#'
#' @param success Logical(1).
#' @param error_message Character(1) or `NA_character_` when `success`
#'   is `TRUE`. If multiple blocks failed, messages are concatenated
#'   with `" | "`.
#' @param tc_name Character(1) â€” e.g. `"tc_persons_crypt"` â€” or
#'   `NA_character_` when `correspondence_table = FALSE` or when
#'   nothing was produced.
#' @param tc_df A tibble or `NULL`. Byte-identical to what was written
#'   to `intermediate_path/tc_<stem>.parquet`.
#' @param start_time,end_time POSIXct(1). `start_time` is captured
#'   before the first I/O; `end_time` after the last I/O attempt
#'   (including inspect xlsx).
#' @param n_rows_processed Integer(1) or `NA_integer_`. Rows in the
#'   final encrypted dataset (not counting the header).
#' @param output_file_path Character(1). Full path to the encrypted
#'   dataset on disk. Used to compute size / sha256 if the file
#'   exists.
#' @return A list with fields `success`, `error_message`, `tc_name`,
#'   `tc_df`, `metrics`. `metrics` is itself a list with `start_time`,
#'   `end_time`, `duration_sec`, `n_rows_processed`,
#'   `output_file_size_bytes`, `output_file_sha256`.
#' @noRd
.make_row_result <- function(success,
                             error_message,
                             tc_name,
                             tc_df,
                             start_time,
                             end_time,
                             n_rows_processed,
                             output_file_path) {

  size_bytes <- NA_real_
  sha256     <- NA_character_
  if (is.character(output_file_path) &&
      length(output_file_path) == 1L &&
      !is.na(output_file_path) &&
      file.exists(output_file_path)) {
    size_bytes <- tryCatch(
      as.numeric(file.info(output_file_path)$size),
      error = function(e) NA_real_)
    sha256 <- tryCatch(
      digest::digest(file = output_file_path, algo = "sha256"),
      error = function(e) NA_character_)
  }

  duration_sec <- tryCatch(
    as.numeric(difftime(end_time, start_time, units = "secs")),
    error = function(e) NA_real_)

  list(
    success        = isTRUE(success),
    error_message  = if (is.null(error_message)) NA_character_
                     else as.character(error_message),
    tc_name        = if (is.null(tc_name)) NA_character_
                     else as.character(tc_name),
    tc_df          = tc_df,
    metrics = list(
      start_time             = start_time,
      end_time               = end_time,
      duration_sec           = duration_sec,
      n_rows_processed       = if (is.null(n_rows_processed)) NA_integer_
                               else as.integer(n_rows_processed),
      output_file_size_bytes = size_bytes,
      output_file_sha256     = sha256
    )
  )
}

#' Does the given path have a `.parquet` extension?
#'
#' Used by the dispatcher to decide whether the streaming engine is
#' applicable. Comparison is case-insensitive. No I/O â€” purely a name
#' check; actual openability is handled by arrow at read time.
#'
#' @param path Character(1).
#' @return Logical(1).
#' @noRd
.is_parquet <- function(path) {
  if (length(path) != 1L || is.na(path)) return(FALSE)
  grepl("\\.parquet$", path, ignore.case = TRUE)
}

#' Does the given path have a `.csv` extension?
#'
#' Symmetric helper to `.is_parquet()`, introduced in Phase 1.D.4.c
#' so the dispatcher can enable the CSV streaming engine.
#'
#' @param path Character(1).
#' @return Logical(1).
#' @noRd
.is_csv <- function(path) {
  if (length(path) != 1L || is.na(path)) return(FALSE)
  grepl("\\.csv$", path, ignore.case = TRUE)
}

#' Process one row of the encryption mask (dispatcher).
#'
#' Thin dispatcher introduced in Phase 1.D.2 and progressively extended:
#' 1.D.4.b (parquet streaming), 1.D.4.c (csv streaming), 1.D.4.d
#' (auto-routing rule + streaming helpers factorised).
#'
#' Routing rule (Phase 1.D.4.d):
#'   - `engine == "in_memory"` â†’ always routes to
#'     `.process_mask_row_in_memory()` (historical code path).
#'   - `engine %in% c("auto", "streaming")` â†’ tries streaming:
#'       * parquet-in + parquet-out â†’ `.process_mask_row_streaming()`;
#'       * csv-in     + csv-out     â†’ `.process_mask_row_csv_streaming()`;
#'       * mixed or non-streamable endpoints (rds, xlsx, parquetâ†’csv,
#'         csvâ†’parquet, â€¦) â†’ silent fallback to
#'         `.process_mask_row_in_memory()` to preserve non-regression.
#'
#' `"auto"` and `"streaming"` are functionally equivalent after
#' 1.D.4.d. The distinction is kept for clarity: `"auto"` is the
#' default promising smart routing; `"streaming"` is an explicit
#' opt-in. We deliberately do **not** make `"streaming"` strict
#' (i.e. erroring on non-streamable inputs) â€” that would be an API
#' change not authorised by CLAUDE.md.
#'
#' Keeping the dispatcher separate from the engines guarantees that
#' the historical code path stays untouched while the streaming
#' engines evolve, protecting non-regression on existing baselines.
#'
#' @inheritParams .process_mask_row_in_memory
#' @param engine One of `"auto"`, `"in_memory"`, `"streaming"`. See
#'   routing rules above.
#' @param chunk_size Integer. Forwarded to the streaming engines only;
#'   ignored by in_memory.
#' @return Invisible list from the selected engine â€” see
#'   `.make_row_result()`. Before Phase 1.D.6.c this was
#'   `invisible(NULL)`; callers who discarded the return value (most
#'   unit tests, the AST-patched baseline `cases.R`) continue to work
#'   unchanged.
#' @noRd
.process_mask_row <- function(sm, input_path, output_path, intermediate_path,
                              encryption_key, algorithm, correspondence_table,
                              engine = "in_memory", chunk_size = 1e6L) {

  try_stream <- engine %in% c("auto", "streaming")
  out_file   <- sm[["encrypted_file"]]

  use_parquet_stream <- try_stream &&
                        .is_parquet(input_path) &&
                        .is_parquet(out_file)
  use_csv_stream     <- try_stream &&
                        .is_csv(input_path) &&
                        .is_csv(out_file)

  if (use_parquet_stream) {
    .process_mask_row_streaming(
      sm                   = sm,
      input_path           = input_path,
      output_path          = output_path,
      intermediate_path    = intermediate_path,
      encryption_key       = encryption_key,
      algorithm            = algorithm,
      correspondence_table = correspondence_table,
      chunk_size           = chunk_size
    )
  } else if (use_csv_stream) {
    .process_mask_row_csv_streaming(
      sm                   = sm,
      input_path           = input_path,
      output_path          = output_path,
      intermediate_path    = intermediate_path,
      encryption_key       = encryption_key,
      algorithm            = algorithm,
      correspondence_table = correspondence_table,
      chunk_size           = chunk_size
    )
  } else {
    # Fallback: `engine = "in_memory"`, or streaming requested on a
    # non-streamable input (rds, xlsx, etc.) or mixed endpoints
    # (parquetâ†’csv, csvâ†’parquet). Historical engine preserves
    # non-regression behaviour in all these cases.
    .process_mask_row_in_memory(
      sm                   = sm,
      input_path           = input_path,
      output_path          = output_path,
      intermediate_path    = intermediate_path,
      encryption_key       = encryption_key,
      algorithm            = algorithm,
      correspondence_table = correspondence_table
    )
  }
}

#' Process one row of the encryption mask â€” in-memory engine.
#'
#' Encapsulates the **historical** per-row processing logic: full load
#' of the input file into RAM via `rio::import()`, then character
#' cleanup, encryption of the requested variables, optional
#' correspondence table, and export of the final dataset + inspect
#' report. Extracted from `.process_mask_row()` in Phase 1.D.2 so that
#' the historical code path can stay strictly unchanged while the
#' streaming engine is being written in Phase 1.D.4.
#'
#' @section FROZEN file outputs (Phase 1.D.3):
#' The files produced by this function are locked by:
#'   - `tests/baseline/outputs/` (byte-level fixtures regenerated by
#'     `tests/baseline/generate_baseline.R`), and
#'   - the explicit invariant tests at the bottom of
#'     `tests/testthat/test-process_mask_row.R` (inspect xlsx layout,
#'     TC parquet distinctness, output column order).
#'
#' Any change that affects the **content** of those files requires:
#'   1. A ticketed motivation in the phase plan.
#'   2. Regeneration of `tests/baseline/outputs/` in the same commit.
#'   3. Review of the impact on the private (enterprise) branch.
#'
#' @section Phase 1.D.6.b â€” retirement of globalenv() pollution:
#' Historically this function assigned the per-variable `<var>_crypt`
#' vectors, the final `<encrypted_file_sans_ext>` dataset and (when
#' `correspondence_table = TRUE`) the `tc_<encrypted_file_sans_ext>`
#' into `globalenv()` via `assign_to_global()`, then read them back via
#' `eval(parse(text = ...))`. Phase 1.D.6.b removes both patterns: the
#' data flows through local variables only; the correspondence table is
#' now stored in the package-private `.cryptRopen_env` (retrievable via
#' [get_correspondence_tables()]) and on disk, mirroring the streaming
#' engines introduced in 1.D.4. File outputs are byte-identical to the
#' historical implementation on matching inputs â€” baseline unchanged.
#'
#' @param sm A one-row data.frame corresponding to one row of the
#'   filtered mask (columns: folder_path, file, encrypted_file,
#'   vars_to_encrypt, vars_to_remove, â€¦).
#' @param input_path Full path to the input dataset file.
#' @param output_path,intermediate_path Directories where outputs are written.
#' @param encryption_key,algorithm,correspondence_table Forwarded from
#'   `crypt_r()`.
#' @return Invisible list with `success`, `error_message`, `tc_name`,
#'   `tc_df`, `metrics` (see `.make_row_result()`). Outputs on disk
#'   and `.cryptRopen_env` side effects are unchanged since
#'   Phase 1.D.6.b / 1.D.6.c â€” the return value is additive, for the
#'   mirai dispatcher to ship results back to `cryptR_collect()`.
#'   Before 1.D.6.c this function returned `invisible(NULL)`; the new
#'   payload is ignored by tests that call the engine for its side
#'   effects only.
#' @noRd
.process_mask_row_in_memory <- function(sm, input_path, output_path, intermediate_path,
                                        encryption_key, algorithm, correspondence_table) {

  requireNamespace("magrittr")

  encrypted_file      <- sm[["encrypted_file"]]
  encrypted_stem      <- stringr::str_remove(encrypted_file, "\\..*$")
  encrypted_file_path <- file.path(output_path, encrypted_file)

  vars_to_encrypt <- sm[["vars_to_encrypt"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  vars_to_remove <- sm[["vars_to_remove"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  # Holds the final in-memory dataset (post-assemble, post-drop) so the
  # export and inspect blocks below can re-use it without reading the
  # output file back. Stays NULL if the import / transform block errors â€”
  # the downstream blocks then short-circuit cleanly.
  assembled_df <- NULL
  tc_name      <- NA_character_
  tc_df        <- NULL

  # Error capture mirrors the historical 3 Ă— try() structure: each
  # block is independent so a failed inspect never masks a successful
  # export. Pre-1.D.6.c we used `try()` and discarded messages silently;
  # now we accumulate them so the recap log in `cryptR_collect()` can
  # report what went wrong per row.
  start_time         <- Sys.time()
  errs               <- character(0)
  transform_exported <- FALSE
  export_ok          <- FALSE

  # --- Import, clean, encrypt, assemble --------------------------------
  tryCatch({
    # Import + character cleanup (empty â†’ NA, trim).
    raw_df <- rio::import(input_path, trust = TRUE) %>%
      dplyr::mutate_if(is.character, \(x0) {
        x0[nchar(stringr::str_trim(x0)) == 0] <- NA
        stringr::str_trim(x0)
      })

    # Encrypt each requested variable. Names follow the historical
    # `<var>_crypt` convention â€” they no longer leak to globalenv().
    crypted_list <- purrr::map(vars_to_encrypt, \(v) {
      crypt_vector(vector = raw_df[[v]],
                   key    = encryption_key,
                   algo   = algorithm)
    })
    names(crypted_list) <- paste0(vars_to_encrypt, "_crypt")

    # Assemble: `<var>_crypt` columns first (in `vars_to_encrypt` order),
    # then original columns (in input order). Matches historical ordering.
    crypted_df <- do.call(dplyr::bind_cols, crypted_list) %>%
      stats::setNames(names(crypted_list))

    full_df <- dplyr::bind_cols(crypted_df, raw_df) %>%
      dplyr::as_tibble()

    # Correspondence table â€” stored in the package-private env AND on disk.
    # `rio::export()` is deliberately kept (not `arrow::write_parquet()`)
    # so the TC parquet stays byte-identical to the pre-refactor baseline.
    # In a mirai daemon the `.cryptRopen_env` populated here is not
    # visible to the parent process; `cryptR_collect()` re-injects
    # `tc_df` (ships back in the return list) into the parent's env.
    if (correspondence_table) {
      tc_name_local <- paste0("tc_", encrypted_stem)
      tc_df_local   <- dplyr::select(full_df, dplyr::all_of(vars_to_encrypt)) %>%
        dplyr::bind_cols(crypted_df) %>%
        dplyr::distinct()
      .store_correspondence_table(name = tc_name_local, df = tc_df_local)
      rio::export(
        tc_df_local,
        file.path(intermediate_path, paste0(tc_name_local, ".parquet")))
      # Only publish to the enclosing function frame once the disk write
      # succeeded, so a half-written TC does not leak into the return
      # value. NB. plain `<-` is load-bearing here: the `tryCatch` body
      # evaluates via `eval(expr, parent.frame())` â€” i.e. in *this*
      # function's frame â€” so `<-` modifies the local binding. `<<-`
      # would walk past this frame up the lexical scope and silently
      # create bindings in globalenv(), leaving `tc_name` and `tc_df`
      # here at their initial NA / NULL. Same rule applies below for
      # `assembled_df` and the `*_ok` flags in every block of every
      # engine; error handlers (true closures) keep `<<-`.
      tc_name <- tc_name_local
      tc_df   <- tc_df_local
    }

    # Drop the original unencrypted columns, then user-specified removes.
    full_df <- dplyr::select(full_df, -dplyr::all_of(vars_to_encrypt))
    if (!all(is.na(vars_to_remove))) {
      full_df <- dplyr::select(full_df, -dplyr::all_of(vars_to_remove))
    }

    assembled_df       <- full_df
    transform_exported <- TRUE
  }, error = function(e) {
    errs <<- c(errs, paste0("transform: ", conditionMessage(e)))
  })

  # --- Export final output ---------------------------------------------
  tryCatch({
    if (!is.null(assembled_df)) {
      rio::export(assembled_df, encrypted_file_path)
      export_ok <- TRUE
    }
  }, error = function(e) {
    errs <<- c(errs, paste0("export: ", conditionMessage(e)))
  })

  # --- Inspect final output --------------------------------------------
  tryCatch({
    if (!is.null(assembled_df)) {
      g <- assembled_df
      i <- inspect(g)
      # NB. The `1:nrow(i)` spelling is load-bearing â€” see the matching
      # comment in `.write_stream_inspect()` for why seq_len()/seq.int()
      # would break baseline on the first cell of the xlsx.
      layout <- rbind(
        c("Obs = ",   nrow(g), rep("", ncol(i) - 1)),
        c("Nvars = ", nrow(i), rep("", ncol(i) - 1)),
        cbind(1:nrow(i), i))
      writexl::write_xlsx(
        layout,
        file.path(output_path,
                  paste0("inspect_", encrypted_file, ".xlsx")))
    }
  }, error = function(e) {
    errs <<- c(errs, paste0("inspect: ", conditionMessage(e)))
  })

  end_time <- Sys.time()
  success  <- transform_exported && export_ok

  invisible(.make_row_result(
    success          = success,
    error_message    = if (length(errs) == 0L) NA_character_
                       else paste(errs, collapse = " | "),
    tc_name          = tc_name,
    tc_df            = tc_df,
    start_time       = start_time,
    end_time         = end_time,
    n_rows_processed = if (!is.null(assembled_df)) nrow(assembled_df)
                       else NA_integer_,
    output_file_path = encrypted_file_path))
}

#' Transform a single stream chunk: cleanup + crypt + column assembly.
#'
#' Introduced in Phase 1.D.4.d to factorise the ~80 lines previously
#' duplicated between `.process_mask_row_streaming()` (parquet) and
#' `.process_mask_row_csv_streaming()` (csv). Pure function â€” no I/O,
#' no globalenv / .cryptRopen_env side effect.
#'
#' Transformation steps (byte-for-byte identical to the historical
#' in_memory engine on matching inputs):
#'   1. Character cleanup: `str_trim()` then empty strings â†’ `NA`.
#'   2. Per-variable encryption via `crypt_vector()`.
#'   3. Column assembly: `<var>_crypt` columns first in `vars_to_encrypt`
#'      order, then non-encrypted input columns in input order.
#'   4. Optional `vars_to_remove` drop (intersect-based â€” missing
#'      columns are silently ignored, matching in_memory behaviour).
#'
#' The returned `tc_chunk` is already `distinct()`. The caller merges
#' chunks across iterations with an outer `bind_rows %>% distinct`.
#'
#' @param chunk A tibble / data.frame â€” one scanner batch.
#' @param vars_to_encrypt,vars_to_remove Character vectors (as split
#'   from the mask row and trimmed).
#' @param encryption_key,algorithm Forwarded to `crypt_vector()`.
#' @param correspondence_table Logical(1). Controls whether `tc_chunk`
#'   is computed (`NULL` when `FALSE`).
#' @return A named list: `out_chunk` (tibble ready to write) and
#'   `tc_chunk` (tibble or `NULL`).
#' @noRd
.transform_stream_chunk <- function(chunk, vars_to_encrypt, vars_to_remove,
                                    encryption_key, algorithm,
                                    correspondence_table) {

  # 1. Character cleanup â€” trim + empty-string-to-NA.
  chunk <- dplyr::mutate(
    chunk,
    dplyr::across(dplyr::where(is.character), \(x0) {
      x0[nchar(stringr::str_trim(x0)) == 0] <- NA
      stringr::str_trim(x0)
    })
  )

  # 2. Encrypt each requested variable.
  crypted <- purrr::map(vars_to_encrypt, \(v) {
    crypt_vector(vector = chunk[[v]], key = encryption_key,
                 algo = algorithm)
  })
  names(crypted) <- paste0(vars_to_encrypt, "_crypt")
  crypted_df <- dplyr::as_tibble(crypted)

  # 3. Per-chunk correspondence rows (if requested).
  tc_chunk <- NULL
  if (correspondence_table) {
    tc_chunk <- dplyr::distinct(
      dplyr::bind_cols(
        dplyr::select(chunk, dplyr::all_of(vars_to_encrypt)),
        crypted_df
      )
    )
  }

  # 4. Assemble output: <var>_crypt first, non-encrypted in input order,
  #    then vars_to_remove dropped.
  non_enc_cols <- setdiff(names(chunk), vars_to_encrypt)
  out_chunk    <- dplyr::bind_cols(
    crypted_df,
    dplyr::select(chunk, dplyr::all_of(non_enc_cols)))

  if (!all(is.na(vars_to_remove))) {
    to_drop <- intersect(vars_to_remove, names(out_chunk))
    if (length(to_drop) > 0L) {
      out_chunk <- dplyr::select(out_chunk, -dplyr::all_of(to_drop))
    }
  }

  list(out_chunk = out_chunk, tc_chunk = tc_chunk)
}

#' Finalise the accumulated correspondence table: store in the package
#' private env + export to parquet on disk.
#'
#' Introduced in Phase 1.D.4.d. Extracted from the two streaming
#' engines whose post-loop finalisation was identical. Idempotent â€” a
#' no-op when `correspondence_table` is `FALSE` or when no rows were
#' accumulated.
#'
#' @param tc_accum The accumulated correspondence tibble, or `NULL`.
#' @param intermediate_path Directory for the parquet output.
#' @param encrypted_stem The encrypted file stem (extension stripped).
#' @param correspondence_table Logical(1).
#' @return Invisible `NULL`.
#' @noRd
.finalize_stream_tc <- function(tc_accum, intermediate_path, encrypted_stem,
                                correspondence_table) {
  if (!correspondence_table || is.null(tc_accum)) return(invisible(NULL))

  tc_name <- paste0("tc_", encrypted_stem)
  .store_correspondence_table(name = tc_name, df = tc_accum)
  arrow::write_parquet(
    tc_accum,
    file.path(intermediate_path,
              paste0(tc_name, ".parquet")))
  invisible(NULL)
}

#' Re-read a freshly written streamed output and emit the companion
#' `inspect_*.xlsx` report.
#'
#' Introduced in Phase 1.D.4.d. Both streaming engines rely on a
#' relecture-based inspect (chunks are not kept in RAM across the
#' scan).
#'
#' Relecture uses `rio::import()` â€” not arrow â€” to preserve strict
#' semantic non-regression with the in_memory engine. Rationale: the
#' in_memory engine calls `inspect()` on the pre-export tibble whose
#' types come from `rio::import()` (e.g. `data.table::fread` for CSV
#' returns `class = c("IDate", "Date")` on date columns, which makes
#' `inspect()` emit two rows per column via its `class`-vectorisation).
#' A prior implementation using `arrow::read_parquet` /
#' `arrow::read_csv_arrow` produced different `class()` tuples and
#' broke the baseline `compare_inspect()` comparison on 11 cases.
#' Reloading via `rio::import()` on the freshly written output
#' reproduces the historical type vector on both readers.
#'
#' Layout (identical to the in_memory engine):
#'   row 1 â€” writexl header artefact (column names),
#'   row 2 â€” `"Obs = "` + total row count,
#'   row 3 â€” `"Nvars = "` + inspect() row count,
#'   rows 4+ â€” inspect() output indexed by row number.
#'
#' @param output_file_path Full path to the encrypted output file.
#' @param output_path Directory where the xlsx will be written.
#' @param encrypted_file Base name of the encrypted file (with
#'   extension) â€” used to build the `inspect_*.xlsx` filename.
#' @return Invisible `NULL`. No-op if the output file is absent.
#' @noRd
.write_stream_inspect <- function(output_file_path,
                                  output_path, encrypted_file) {
  if (!file.exists(output_file_path)) return(invisible(NULL))

  out_df <- as.data.frame(rio::import(output_file_path, trust = TRUE))
  i <- inspect(out_df)
  # NB. The `1:nrow(i)` spelling (not `seq_len(nrow(i))`) is load-bearing:
  # `cbind()` names the new column from the *expression* passed to it, so
  # the historical in_memory engine emits a data.frame whose first column
  # is named "1:nrow(i)". writexl writes this name as the header row, which
  # readxl::read_xlsx(col_names = FALSE) then surfaces as the value of
  # row 1, column 1 in the compared xlsx. Using any other expression
  # (seq_len(), seq.int()â€¦) breaks baseline on this single cell.
  layout <- rbind(
    c("Obs = ",   nrow(out_df), rep("", ncol(i) - 1)),
    c("Nvars = ", nrow(i),      rep("", ncol(i) - 1)),
    cbind(1:nrow(i), i))
  writexl::write_xlsx(
    layout,
    file.path(output_path,
              paste0("inspect_", encrypted_file, ".xlsx")))
  invisible(NULL)
}

#' Process one row of the encryption mask â€” streaming engine (parquet).
#'
#' Introduced in Phase 1.D.4.b, refactored in 1.D.4.d to delegate
#' chunk transformation, TC finalisation and inspect reporting to
#' shared helpers (`.transform_stream_chunk()`, `.finalize_stream_tc()`,
#' `.write_stream_inspect()`).
#'
#' Streams the input parquet file through an arrow Scanner by chunks
#' of `chunk_size` rows, encrypts each chunk in memory, writes the
#' result incrementally to the output parquet file via
#' `arrow::ParquetFileWriter`, and builds the correspondence table by
#' accumulating per-chunk `distinct()` rows.
#'
#' Handles **parquet-in / parquet-out only** (dispatcher precondition).
#'
#' Behavioural guarantees (vs. the in-memory engine on matching input):
#'   - Output rows identical (same values, same types, same order).
#'   - Output column order identical: `<var>_crypt` first in
#'     `vars_to_encrypt` order, then remaining input columns in input
#'     order (`vars_to_remove` applied last).
#'   - Character cleanup identical: `str_trim()` + empty â†’ NA.
#'   - Correspondence table contents identical (modulo row order, also
#'     non-deterministic in the in-memory engine).
#'   - `inspect_*.xlsx` layout identical.
#'
#' Deliberate differences (Option B, validated 2026-04-22):
#'   - **No pollution of `globalenv()`**. TC lives in `.cryptRopen_env`
#'     (retrievable via `get_correspondence_tables()`) and on disk.
#'   - `assign_to_global()` + `eval(parse(text = ...))` are not used.
#'
#' @param sm,input_path,output_path,intermediate_path,encryption_key,algorithm,correspondence_table
#'   Forwarded from the dispatcher â€” see `.process_mask_row_in_memory()`.
#' @param chunk_size Integer(1). Arrow Scanner `batch_size`. Only
#'   affects memory usage and performance; results are invariant.
#' @return Invisible list (see `.make_row_result()`). Disk side
#'   effects + `.cryptRopen_env` population unchanged; return value
#'   added in Phase 1.D.6.c for the mirai collect path.
#' @noRd
.process_mask_row_streaming <- function(sm, input_path, output_path, intermediate_path,
                                        encryption_key, algorithm, correspondence_table,
                                        chunk_size = 1e6L) {

  requireNamespace("magrittr")
  requireNamespace("arrow")

  encrypted_file   <- sm[["encrypted_file"]]
  encrypted_stem   <- stringr::str_remove(encrypted_file, "\\..*$")
  output_file_path <- file.path(output_path, encrypted_file)

  vars_to_encrypt <- sm[["vars_to_encrypt"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  vars_to_remove <- sm[["vars_to_remove"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  tc_accum     <- NULL
  writer       <- NULL
  sink         <- NULL
  n_rows_accum <- 0L
  start_time   <- Sys.time()
  errs         <- character(0)
  stream_ok    <- FALSE

  # --- Read / transform / write by chunks -------------------------------
  tryCatch({
    ds      <- arrow::open_dataset(input_path, format = "parquet")
    scanner <- arrow::Scanner$create(ds, batch_size = as.integer(chunk_size))
    reader  <- scanner$ToRecordBatchReader()

    repeat {
      batch <- reader$read_next_batch()
      if (is.null(batch)) break

      chunk <- dplyr::as_tibble(as.data.frame(batch))
      tf    <- .transform_stream_chunk(
        chunk                = chunk,
        vars_to_encrypt      = vars_to_encrypt,
        vars_to_remove       = vars_to_remove,
        encryption_key       = encryption_key,
        algorithm            = algorithm,
        correspondence_table = correspondence_table)

      if (correspondence_table && !is.null(tf$tc_chunk)) {
        tc_accum <- if (is.null(tc_accum)) tf$tc_chunk
                    else dplyr::distinct(dplyr::bind_rows(tc_accum, tf$tc_chunk))
      }

      arrow_tbl <- arrow::as_arrow_table(tf$out_chunk)
      n_rows_accum <- n_rows_accum + nrow(tf$out_chunk)

      # First chunk fixes the output schema; subsequent chunks must
      # conform. Character cleanup + crypt_vector() are type-stable,
      # so the schema is stable across chunks by construction.
      # Arrow-R quirks (see 1.D.4.b commit 38d8151d):
      #   - `sink` must be an OutputStream (a character path is not
      #     accepted â€” hence the FileOutputStream wrapper);
      #   - the default `properties` built by
      #     `ParquetWriterProperties$create()` fails unless
      #     `column_names` is provided explicitly;
      #   - `WriteTable()` also requires a non-default `chunk_size`.
      if (is.null(writer)) {
        sink   <- arrow::FileOutputStream$create(output_file_path)
        writer <- arrow::ParquetFileWriter$create(
          schema     = arrow_tbl$schema,
          sink       = sink,
          properties = arrow::ParquetWriterProperties$create(
            column_names = names(arrow_tbl)))
      }
      writer$WriteTable(arrow_tbl, chunk_size = arrow_tbl$num_rows)
    }

    if (!is.null(writer)) writer$Close()
    if (!is.null(sink))   sink$close()
    # `<-` (not `<<-`) because the tryCatch body evaluates in this
    # function's frame â€” see the long comment in the in_memory engine.
    stream_ok <- TRUE
  }, error = function(e) {
    errs <<- c(errs, paste0("stream: ", conditionMessage(e)))
    # Ensure writer/sink are closed on partial streams so the file is
    # flushable; otherwise the partial output stays locked on Windows.
    try(if (!is.null(writer)) writer$Close(), silent = TRUE)
    try(if (!is.null(sink))   sink$close(),   silent = TRUE)
  })

  # --- Correspondence table (shared finaliser) --------------------------
  tryCatch({
    .finalize_stream_tc(tc_accum, intermediate_path, encrypted_stem,
                        correspondence_table)
  }, error = function(e) {
    errs <<- c(errs, paste0("tc_finalize: ", conditionMessage(e)))
  })

  # --- Inspect (shared; rio::import for type fidelity) ------------------
  tryCatch({
    .write_stream_inspect(output_file_path, output_path, encrypted_file)
  }, error = function(e) {
    errs <<- c(errs, paste0("inspect: ", conditionMessage(e)))
  })

  end_time <- Sys.time()
  tc_name  <- if (correspondence_table && !is.null(tc_accum))
                paste0("tc_", encrypted_stem) else NA_character_

  invisible(.make_row_result(
    success          = stream_ok && file.exists(output_file_path),
    error_message    = if (length(errs) == 0L) NA_character_
                       else paste(errs, collapse = " | "),
    tc_name          = tc_name,
    tc_df            = tc_accum,
    start_time       = start_time,
    end_time         = end_time,
    n_rows_processed = if (n_rows_accum > 0L) n_rows_accum else NA_integer_,
    output_file_path = output_file_path))
}

#' Process one row of the encryption mask â€” streaming engine (CSV).
#'
#' Introduced in Phase 1.D.4.c, refactored in 1.D.4.d to share chunk
#' transformation / TC finalisation / inspect reporting with the
#' parquet streaming engine.
#'
#' Streams the input CSV via `arrow::open_csv_dataset()` + Scanner,
#' encrypts each chunk in memory, appends each chunk to the output CSV
#' via `utils::write.table(append = TRUE)`. `arrow::CsvWriter` is
#' intentionally not used: it is not exported in every installed
#' `arrow` version. `utils::write.table` preserves the streaming
#' property on the read/transform side with no extra dependency.
#'
#' Handles **csv-in / csv-out only** (dispatcher precondition). The
#' correspondence table is still written as parquet (symmetric with
#' in_memory + parquet streaming): only the main encrypted dataset is
#' CSV.
#'
#' Semantic guarantees vs. the in-memory engine: identical row set,
#' identical output column order, identical character cleanup rules.
#' **Byte-level equality is not guaranteed** â€” base R's writer quoting
#' rules differ from `rio::export()` / `data.table::fwrite`. Tests
#' compare via re-read content (`rowset()`), not by file hash.
#'
#' Like the parquet streaming engine: no globalenv pollution, TC in
#' `.cryptRopen_env` + on disk.
#'
#' @inheritParams .process_mask_row_streaming
#' @return Invisible list (see `.make_row_result()`). Disk side
#'   effects unchanged; typed return added in Phase 1.D.6.c.
#' @noRd
.process_mask_row_csv_streaming <- function(sm, input_path, output_path, intermediate_path,
                                            encryption_key, algorithm, correspondence_table,
                                            chunk_size = 1e6L) {

  requireNamespace("magrittr")
  requireNamespace("arrow")

  encrypted_file   <- sm[["encrypted_file"]]
  encrypted_stem   <- stringr::str_remove(encrypted_file, "\\..*$")
  output_file_path <- file.path(output_path, encrypted_file)

  vars_to_encrypt <- sm[["vars_to_encrypt"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  vars_to_remove <- sm[["vars_to_remove"]] %>%
    stringr::str_split(",") %>% unlist() %>%
    stringr::str_trim()

  tc_accum     <- NULL
  first_chunk  <- TRUE
  n_rows_accum <- 0L
  start_time   <- Sys.time()
  errs         <- character(0)
  stream_ok    <- FALSE

  # --- Read / transform / write by chunks -------------------------------
  tryCatch({
    ds      <- arrow::open_csv_dataset(input_path)
    scanner <- arrow::Scanner$create(ds, batch_size = as.integer(chunk_size))
    reader  <- scanner$ToRecordBatchReader()

    repeat {
      batch <- reader$read_next_batch()
      if (is.null(batch)) break

      chunk <- dplyr::as_tibble(as.data.frame(batch))
      tf    <- .transform_stream_chunk(
        chunk                = chunk,
        vars_to_encrypt      = vars_to_encrypt,
        vars_to_remove       = vars_to_remove,
        encryption_key       = encryption_key,
        algorithm            = algorithm,
        correspondence_table = correspondence_table)

      if (correspondence_table && !is.null(tf$tc_chunk)) {
        tc_accum <- if (is.null(tc_accum)) tf$tc_chunk
                    else dplyr::distinct(dplyr::bind_rows(tc_accum, tf$tc_chunk))
      }

      n_rows_accum <- n_rows_accum + nrow(tf$out_chunk)

      # Append chunk to CSV output. First chunk writes the header and
      # creates the file; subsequent chunks append without header.
      utils::write.table(
        as.data.frame(tf$out_chunk),
        file      = output_file_path,
        sep       = ",",
        dec       = ".",
        qmethod   = "double",
        row.names = FALSE,
        col.names = first_chunk,
        append    = !first_chunk)
      first_chunk <- FALSE
    }
    # `<-` (not `<<-`) because the tryCatch body evaluates in this
    # function's frame â€” see the long comment in the in_memory engine.
    stream_ok <- TRUE
  }, error = function(e) {
    errs <<- c(errs, paste0("stream: ", conditionMessage(e)))
  })

  # --- Correspondence table (shared finaliser) --------------------------
  tryCatch({
    .finalize_stream_tc(tc_accum, intermediate_path, encrypted_stem,
                        correspondence_table)
  }, error = function(e) {
    errs <<- c(errs, paste0("tc_finalize: ", conditionMessage(e)))
  })

  # --- Inspect (shared; rio::import for type fidelity) ------------------
  tryCatch({
    .write_stream_inspect(output_file_path, output_path, encrypted_file)
  }, error = function(e) {
    errs <<- c(errs, paste0("inspect: ", conditionMessage(e)))
  })

  end_time <- Sys.time()
  tc_name  <- if (correspondence_table && !is.null(tc_accum))
                paste0("tc_", encrypted_stem) else NA_character_

  invisible(.make_row_result(
    success          = stream_ok && file.exists(output_file_path),
    error_message    = if (length(errs) == 0L) NA_character_
                       else paste(errs, collapse = " | "),
    tc_name          = tc_name,
    tc_df            = tc_accum,
    start_time       = start_time,
    end_time         = end_time,
    n_rows_processed = if (n_rows_accum > 0L) n_rows_accum else NA_integer_,
    output_file_path = output_file_path))
}
